STAGE 2 - Peer Rankings:
Model: anthropic/claud
Ranking: {{ $('evaluate_a').item.json.Raiting_1 }}

Model: openai/gpt
Ranking: {{ $('evaluate_b').item.json.Raiting_2 }}

