const itemData = items[0].json; // ← ПРАВИЛЬНО!

function parseRanking(text) {
  const ranking = {};
  const lines = text.split('\n');
  let inFinalRanking = false;

  lines.forEach(line => {
    if (line.includes('FINAL RANKING')) {
      inFinalRanking = true;
    }
    if (inFinalRanking && line.trim().length > 0) {
      const match = line.match(/(\d+)\.\s*(Response [A-D])/);
      if (match) {
        ranking[match[2]] = parseInt(match[1]);
      }
    }
  });

  return ranking;
}

const allRankings = [];
['Raiting_1', 'Raiting_2', 'Raiting_3', 'Raiting_4'].forEach(key => {
  if (itemData[key]) {
    const parsed = parseRanking(itemData[key]);
    allRankings.push(parsed);
    console.log(`Parsed ${key}:`, parsed);
  }
});

const aggregated = {};
['Response A', 'Response B', 'Response C', 'Response D'].forEach(resp => {
  aggregated[resp] = { positions: [] };
});

allRankings.forEach(ranking => {
  Object.entries(ranking).forEach(([response, position]) => {
    if (aggregated[response]) {
      aggregated[response].positions.push(position);
    }
  });
});

Object.keys(aggregated).forEach(response => {
  const positions = aggregated[response].positions;
  if (positions.length > 0) {
    const avg = positions.reduce((a,b) => a+b, 0) / positions.length;
    aggregated[response].average = parseFloat(avg.toFixed(2));
    aggregated[response].count = positions.length;
    aggregated[response].total = positions.reduce((a,b) => a+b, 0);
  }
});

const sorted = Object.entries(aggregated)
  .sort((a, b) => a[1].average - b[1].average)
  .reduce((obj, [key, val]) => { obj[key] = val; return obj; }, {});

return [{
  json: {
    raw_rankings: allRankings,
    aggregated_rankings: sorted,
    best_response: Object.keys(sorted)[0],
    best_score: sorted[Object.keys(sorted)[0]].average,
    rankings_count: allRankings.length
  }
}];
